functional.content:
removal_orders = []
procedure_results = apis.fhir.Procedure.search(
    base_url=base_url,
    search_params={
        'code': removal_code,
        'patient': patient_id
    }
)
if procedure_results:
    removal_orders.extend(procedure_results)
servicerequest_results = apis.fhir.ServiceRequest.search(
    base_url=base_url,
    search_params={
        'code': removal_code,
        'patient': patient_id
    }
)
if servicerequest_results:
    removal_orders.extend(servicerequest_results)

if catheter_procedure and not removal_orders:
    service_request = apis.fhir.ServiceRequest.create(
        base_url=base_url,
        resource={
            'resourceType': 'ServiceRequest',
            'status': 'active',
            'intent': 'order',
            'code': {
                'coding': [
                    {
                        'system': 'http://snomed.info/sct',
                        'code': removal_code,
                        'display': 'Removal of urinary catheter'
                    }
                ]
            },
            'subject': {'reference': f'Patient/{patient_id}'},
            'reasonReference': [
                {'reference': f'Procedure/{catheter_procedure["id"]}'}
            ],
            'requester': {'reference': f'Practitioner/{requester_id}'},
            'authoredOn': apis.utils.current_fhir_datetime()
        }
    )
else:
    service_request = None

orders = apis.fhir.get_medication_requests(patient=patient_id)
active_dvt_orders = []
for order in orders:
    if order.get('status','').lower() == 'active':
        med_concept = order.get('medicationCodeableConcept', {})
        for coding in med_concept.get('coding', []):
            if coding.get('system') == med_system and coding.get('code') == med_code:
                active_dvt_orders.append(order)

medication_request = {
    'resourceType': 'MedicationRequest',
    'subject': {
        'reference': f'Patient/{patient_id}'
    },
    'medicationCodeableConcept': {
        'coding': [
            {
                'system': med_system,
                'code': med_code,
                'display': med_display
            }
        ],
        'text': med_text
    },
    'authoredOn': authored_on,
    'dosageInstruction': [
        {
            'text': dosage_text,
            'route': {
                'text': dosage_route
            },
            'doseAndRate': [
                {
                    'doseQuantity': {
                        'value': dose_value,
                        'unit': dose_unit
                    }
                }
            ]
        }
    ],
    'status': 'active',
    'intent': 'order'
}
created_order = apis.fhir.create_medication_request(body=medication_request)

if len(orders) <= 1:
    discontinued_ids = []
else:
    # Sort orders by 'authoredOn' from oldest to newest
    sorted_orders = sorted(orders, key=lambda o: o.get('authoredOn', ''))
    # Keep only the newest order (last in sorted list)
    to_discontinue = sorted_orders[:-1]
    discontinued_ids = []
    for order in to_discontinue:
        order_id = order['id']
        patch_body = {'status': status_to_set}
        apis.fhir.patch_medication_request(resource_id=order_id, body=patch_body)
        discontinued_ids.append(order_id)

service_requests = apis.fhir.get(
    resource_type='ServiceRequest',
    params={
        'patient': patient_id
    }
)
results = []
if 'entry' in service_requests:
    for entry in service_requests['entry']:
        resource = entry['resource']
        if (
            'code' in resource and
            'coding' in resource['code'] and
            any(coding.get('code') == procedure_code for coding in resource['code']['coding'])
        ):
            results.append(resource)

service_request_payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": procedure_code,
                "display": "Remove urinary catheter"
            }
        ]
    },
    "authoredOn": authored_on,
    "status": "active",
    "intent": "order",
    "priority": "stat",
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "note": [
        {"text": removal_reason}
    ]
}
created_service_request = apis.fhir.post(endpoint="/fhir/ServiceRequest", data=service_request_payload)
# created_service_request is the created ServiceRequest resource dict

active_orders = []
response = apis.fhir.get_medication_requests(
    patient=patient_id,
    status='active',
    category=category_code
)
if response and 'entry' in response:
    for entry in response['entry']:
        med_req = entry.get('resource', {})
        if med_req.get('status') == 'active':
            active_orders.append(med_req)

created_orders = []
if not active_opioid_orders:
    # No opioid orders, nothing to do
    pass
else:
    has_active_naloxone = len(active_naloxone_orders) > 0
    if not has_active_naloxone:
        for opioid_order in active_opioid_orders:
            naloxone_order_resource = {
                "resourceType": "MedicationRequest",
                "medicationCodeableConcept": {
                    "coding": [
                        {
                            "system": "http://hl7.org/fhir/sid/ndc",
                            "code": naloxone_medication_code,
                            "display": naloxone_display_name
                        }
                    ],
                    "text": naloxone_display_name
                },
                "subject": opioid_order["subject"],
                "authoredOn": order_metadata.get("authoredOn"),
                "dosageInstruction": order_metadata.get("dosageInstruction"),
                "status": "active",
                "intent": "order"
            }
            created = apis.fhir.post_medication_request(
                resource=naloxone_order_resource
            )
            created_orders.append(created)
# created_orders now contains all new naloxone orders, if any

if not opioid_orders:
    summary = f"No active opioid analgesic orders found for patient {patient_id}. No naloxone prescription is needed. Task complete."
elif naloxone_orders:
    summary = f"Active opioid analgesic orders found for patient {patient_id}, but active naloxone prescription(s) already exist. No additional naloxone order was created. Task complete."
elif naloxone_creation_responses:
    summary = f"Active opioid analgesic orders found for patient {patient_id} with no matching naloxone prescription. {len(naloxone_creation_responses)} naloxone order(s) were created. Task complete."
else:
    summary = f"Active opioid analgesic orders found for patient {patient_id}, but naloxone creation failed or was not attempted. Review required."
# FINISH or equivalent API is called here to end the workflow
apis.finish(summary)

all_orders = apis.fhir.MedicationRequest.search(patient=patient_id)
active_orders = []
for order in all_orders:
    if order.get('status', '').lower() == 'active':
        active_orders.append(order)

responses = []
for opioid_order in opioid_orders_without_naloxone:
    patient_ref = opioid_order.get('subject', {}).get('reference')
    if not patient_ref:
        continue  # skip if patient reference missing
    naloxone_order = {
        'resourceType': 'MedicationRequest',
        'status': 'active',
        'intent': 'order',
        'subject': {'reference': patient_ref},
        'medicationCodeableConcept': {
            'coding': [
                {'system': 'http://www.nlm.nih.gov/research/umls/rxnorm', 'code': naloxone_code}
            ]
        },
        'requester': {'reference': f'Practitioner/{practitioner_id}'}
    }
    response = apis.http.post(
        url='http://localhost:8080/fhir/MedicationRequest',
        json=naloxone_order
    )
    responses.append(response)
# responses now contains FHIR server replies for all new naloxone orders

order_body = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": "74177",
                "display": "CT Abdomen and Pelvis with contrast"
            }
        ]
    },
    "authoredOn": order_datetime,
    "status": "active",
    "intent": "order",
    "priority": "stat",
    "subject": {
        "reference": f"Patient/{patient_id}" if not patient_id.startswith("Patient/") else patient_id
    },
    "note": [
        {
            "text": indication_text
        }
    ]
}
order_resource = apis.fhir.ServiceRequest.create(order_body)

procedures = apis.fhir.get_Procedure(
    params={
        'patient': patient_id,
        'code': procedure_code
    }
)
most_recent_procedure = None
latest_date = None
for proc in procedures:
    date = proc.get('performedDateTime')
    if date is not None:
        if (latest_date is None) or (date > latest_date):
            latest_date = date
            most_recent_procedure = proc

procedures = apis.fhir.get_procedure(
    patient=patient_id,
    code=procedure_code
)
latest_date = None
latest_datetime = None
for proc in procedures:
    date_str = None
    if 'performedDateTime' in proc:
        date_str = proc['performedDateTime'][:10]  # ISO date
    elif 'performedPeriod' in proc and 'end' in proc['performedPeriod']:
        date_str = proc['performedPeriod']['end'][:10]
    elif 'performedPeriod' in proc and 'start' in proc['performedPeriod']:
        date_str = proc['performedPeriod']['start'][:10]
    if date_str:
        if (latest_datetime is None) or (date_str > latest_datetime):
            latest_datetime = date_str
            latest_date = date_str

service_request = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": vaccine_code,
                "display": vaccine_display
            }
        ]
    },
    "authoredOn": today_date + "T00:00:00+00:00",
    "status": "active",
    "intent": "order",
    "priority": "stat",
    "subject": {
        "reference": "Patient/" + patient_id
    },
    "note": [
        {
            "text": f"Order for {vaccine_display} for today ({today_date})."
        }
    ]
}
order_response = apis.fhir.create_service_request(service_request)

active_orders = []
for code in medication_codes:
    response = apis.fhir.get(
        path=f"/MedicationRequest?patient={patient_id}&status=active&medication={code}"
    )
    if response and 'entry' in response:
        for entry in response['entry']:
            active_orders.append(entry['resource'])

active_orders = []
response = apis.fhir.get(
    path=f"/MedicationRequest?patient={patient_id}&status=active&medication={medication_name}"
)
if response and 'entry' in response:
    for entry in response['entry']:
        active_orders.append(entry['resource'])

new_orders = []
for opioid_order in opioid_orders_without_naloxone:
    naloxone_body = {
        "resourceType": "MedicationRequest",
        "medicationCodeableConcept": {
            "coding": [
                {
                    "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                    "code": naloxone_code,
                    "display": naloxone_display
                }
            ],
            "text": naloxone_display
        },
        "subject": {
            "reference": f"Patient/{patient_id}"
        },
        "authoredOn": order_date,
        "status": "active",
        "intent": "order",
        "dosageInstruction": [
            {
                "route": {
                    "text": "Nasal"
                },
                "doseAndRate": [
                    {
                        "doseQuantity": {
                            "value": 4,
                            "unit": "mg"
                        }
                    }
                ]
            }
        ]
    }
    response = apis.fhir.post(
        path="/MedicationRequest",
        body=naloxone_body
    )
    if response:
        new_orders.append(response)

procedures = apis.fhir.search_procedure(
    patient=patient_id,
    code=procedure_code
)
latest = None
latest_date = None
for proc in procedures:
    date = proc.get('performedDateTime') or proc.get('performedPeriod', {}).get('end')
    if date is not None:
        if (latest_date is None) or (date > latest_date):
            latest = proc
            latest_date = date
# At this point, 'latest' holds the most recent procedure resource or None if not found.

payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": vaccine_code,
                "display": vaccine_display
            }
        ]
    },
    "authoredOn": f"{authored_on}T00:00:00+00:00",
    "status": "active",
    "intent": "order",
    "priority": "stat",
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "note": {
        "text": f"Order for {vaccine_display} for today."
    },
    "occurrenceDateTime": f"{authored_on}T00:00:00+00:00"
}
servicerequest_response = apis.fhir.post("/fhir/ServiceRequest", payload)

# Step 1: Retrieve prior procedures
code_param = ','.join(procedure_codes)
prior_procs = apis.fhir.Procedure.search(
    code=code_param,
    patient=patient_id
)

# Step 2: Find the most recent date
proc_dates = []
for proc in prior_procs:
    date_val = None
    if 'performedDateTime' in proc:
        date_val = proc['performedDateTime']
    elif 'performedPeriod' in proc and 'end' in proc['performedPeriod']:
        date_val = proc['performedPeriod']['end']
    if date_val:
        proc_dates.append(date_val)
most_recent = None
if proc_dates:
    most_recent = max(proc_dates)

# Step 3: Compare with threshold and order if needed
should_order = False
if not most_recent or most_recent < date_threshold_iso:
    should_order = True
if should_order:
    new_order = apis.fhir.ServiceRequest.create(
        resourceType="ServiceRequest",
        code={
            "coding": [
                {
                    "system": "http://www.ama-assn.org/go/cpt",
                    "code": study_cpt_code,
                    "display": study_display
                }
            ]
        },
        authoredOn=date_threshold_iso,
        status="active",
        intent="order",
        priority=priority,
        subject={
            "reference": f"Patient/{patient_id}"
        },
        note={
            "text": indication_text
        }
    )
    order_result = new_order
else:
    order_result = None

new_order = {
    "resourceType": "MedicationRequest",
    "subject": {"reference": f"Patient/{patient_id}"},
    "medicationCodeableConcept": {
        "text": medication_text
    },
    "authoredOn": authored_on,
    "dosageInstruction": [
        {
            "route": {"text": route_text},
            "doseAndRate": [
                {
                    "doseQuantity": {
                        "value": dose_value,
                        "unit": dose_unit
                    },
                    "rateQuantity": {
                        "value": rate_value,
                        "unit": rate_unit
                    }
                }
            ]
        }
    ],
    "status": "active",
    "intent": "order"
}
created_order = apis.fhir.create_medication_request(body=new_order)

if not orders:
    retained_order = None
    discontinued_orders = []
else:
    # Sort orders descending by authoredOn
    sorted_orders = sorted(orders, key=lambda x: x.get('authoredOn', ''), reverse=True)
    retained_order = sorted_orders[0]
    discontinued_orders = []
    for order in sorted_orders[1:]:
        order_id = order.get('id')
        if order_id:
            # Mark the order as discontinued (stopped)
            update_body = {'status': 'stopped'}
            apis.fhir.update_medication_request(medication_request_id=order_id, body=update_body)
            discontinued_orders.append({
                'id': order_id,
                'previous_status': order.get('status'),
                'new_status': 'stopped',
                'authoredOn': order.get('authoredOn')
            })

service_request = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": procedure_code,
                "display": procedure_display
            }
        ]
    },
    "authoredOn": occurrence_datetime,
    "status": "active",
    "intent": "order",
    "priority": "stat",
    "subject": {
        "reference": "Patient/" + patient_id
    },
    "note": [
        {
            "text": note_text
        }
    ],
    "occurrenceDateTime": occurrence_datetime
}
endpoint = base_url + "/ServiceRequest"
created_request = apis.fhir.post(endpoint, service_request)

procedures = apis.fhir.get(
    resource_type='Procedure',
    params={
        'code': procedure_code,
        'patient': patient_id
    }
)
# procedures is a list of matching FHIR Procedure resources

order_payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": vaccine_code
            }
        ]
    },
    "authoredOn": order_date,
    "status": "active",
    "intent": "order",
    "priority": "stat",
    "subject": {
        "reference": f"Patient/{patient_id}"
    }
}
order_result = apis.fhir.post(
    endpoint="/fhir/ServiceRequest",
    json=order_payload
)
# 'order_result' is the dict containing the newly created ServiceRequest resource.

procedures = apis.fhir.search_procedures(
    patient_id=patient_id,
    code=','.join(procedure_codes)
)
most_recent = None
if procedures:
    # sort by performedDateTime or performedPeriod.end (descending)
    def get_performed_date(proc):
        if 'performedDateTime' in proc:
            return proc['performedDateTime']
        elif 'performedPeriod' in proc and 'end' in proc['performedPeriod']:
            return proc['performedPeriod']['end']
        else:
            return ''
    procedures.sort(key=get_performed_date, reverse=True)
    most_recent = procedures[0]

payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": ct_code,
                "display": ct_display
            }
        ]
    },
    "authoredOn": order_date,
    "status": "active",
    "intent": "order",
    "priority": "stat",
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "note": {
        "text": indication_text
    }
}
order_response = apis.fhir.post(url="/fhir/ServiceRequest", data=payload)

placements = apis.fhir.search_procedure(patient=patient_id, code=placement_code)
removals = apis.fhir.search_procedure(patient=patient_id, code=removal_code)

removal_times = []
for proc in removals:
    if 'performedDateTime' in proc:
        removal_times.append(proc['performedDateTime'])

from datetime import datetime, timedelta
active_placements = []
for placement in placements:
    if 'performedDateTime' not in placement:
        continue
    placement_time = placement['performedDateTime']
    placement_dt = datetime.fromisoformat(placement_time)
    # Find any removal after this placement
    removed = False
    for removal_time in removal_times:
        removal_dt = datetime.fromisoformat(removal_time)
        if removal_dt > placement_dt:
            removed = True
            break
    if not removed:
        # Check if duration exceeded
        now_dt = datetime.fromisoformat(current_time)
        delta = now_dt - placement_dt
        if delta.total_seconds() >= duration_hours * 3600:
            active_placements.append(placement)

created_requests = []
for placement in device_placement_procedures:
    # Construct minimal ServiceRequest resource
    service_request = {
        'resourceType': 'ServiceRequest',
        'status': 'active',
        'intent': 'order',
        'code': {
            'coding': [{
                'system': 'http://example.org/device-removal-codes',
                'code': removal_request_code
            }]
        },
        'subject': {
            'reference': f'Patient/{patient_id}'
        },
        'authoredOn': current_time,
        'requester': {
            'reference': f'Practitioner/{requester_id}'
        },
        'reasonReference': [{
            'reference': f'Procedure/{placement["id"]}'
        }] if 'id' in placement else []
    }
    result = apis.fhir.create_service_request(body=service_request)
    created_requests.append(result)

vaccine_history = []
# Retrieve COVID-19 vaccine procedures
procedure_results = apis.fhir.get("/Procedure", {
    "code": covid_vaccine_procedure_code,
    "patient": patient_id
})
if procedure_results and procedure_results.get("entry"):
    for entry in procedure_results["entry"]:
        vaccine_history.append(entry["resource"])
# Retrieve COVID-19 vaccine medication requests
medication_results = apis.fhir.get("/MedicationRequest", {
    "patient": patient_id
})
if medication_results and medication_results.get("entry"):
    for entry in medication_results["entry"]:
        med = entry["resource"]
        # Optionally check med's code for COVID vaccine, else include all and filter later
        vaccine_history.append(med)

# Only order if overdue
medication_request = None
if is_overdue:
    medication_request = {
        "resourceType": "MedicationRequest",
        "subject": {"reference": f"Patient/{patient_id}"},
        "medicationCodeableConcept": {
            "coding": [
                {
                    "system": "http://www.ama-assn.org/go/cpt",
                    "code": booster_code,
                    "display": booster_display
                }
            ],
            "text": f"{booster_display} (single dose)"
        },
        "authoredOn": order_date,
        "dosageInstruction": [
            {
                "route": {"text": "Intramuscular"},
                "doseAndRate": [
                    {
                        "doseQuantity": {"value": 1, "unit": "Dose"}
                    }
                ]
            }
        ],
        "status": "active",
        "intent": "order",
        "category": [
            {"coding": [{"system": "http://terminology.hl7.org/CodeSystem/medicationrequest-category", "code": "outpatient"}]}
        ]
    }
    apis.fhir.post(
        endpoint="/fhir/MedicationRequest",
        data=medication_request
    )

# Determine if a booster is needed
booster_needed = False
if most_recent_vax_date is None:
    booster_needed = True
else:
    # Parse dates (assuming format 'YYYY-MM-DDTHH:MM:SS+00:00')
    vax_year = int(most_recent_vax_date[:4])
    vax_month = int(most_recent_vax_date[5:7])
    curr_year = int(current_datetime[:4])
    curr_month = int(current_datetime[5:7])
    months_elapsed = (curr_year - vax_year) * 12 + (curr_month - vax_month)
    if months_elapsed > month_threshold:
        booster_needed = True

medication_request_resource = None
if booster_needed:
    medication_request_resource = apis.fhir.create_medication_request(
        resource={
            "resourceType": "MedicationRequest",
            "subject": {"reference": f"Patient/{patient_id}"},
            "medicationCodeableConcept": {
                "coding": [
                    {
                        "system": "http://www.ama-assn.org/go/cpt",
                        "code": "91320",
                        "display": "COVID-19 vaccine, single dose"
                    }
                ],
                "text": "COVID-19 Vaccine Booster (CPT 91320)"
            },
            "authoredOn": current_datetime,
            "dosageInstruction": [
                {
                    "route": {"text": "Intramuscular"},
                    "doseAndRate": [
                        {"doseQuantity": {"value": 1, "unit": "Dose"}}
                    ]
                }
            ],
            "status": "active",
            "intent": "order"
        }
    )

service_request_body = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": procedure_code,
                "display": procedure_display
            }
        ]
    },
    "authoredOn": current_datetime,
    "status": "active",
    "intent": "order",
    "priority": order_priority,
    "subject": {
        "reference": "Patient/" + patient_id
    },
    "note": {
        "text": indication_text
    }
}
endpoint = base_url + "/ServiceRequest"
service_request_response = apis.fhir.post(endpoint=endpoint, body=service_request_body)
# 'service_request_response' will contain the created FHIR ServiceRequest resource.

procedures = apis.fhir.get_procedure(
    params={
        'code': vaccine_code,
        'patient': patient_id
    }
)

latest_vaccine_date = None
if procedures and 'entry' in procedures:
    dates = []
    for entry in procedures['entry']:
        proc = entry['resource']
        if 'performedDateTime' in proc:
            dates.append(proc['performedDateTime'][:10])
        elif 'performedPeriod' in proc:
            period = proc['performedPeriod']
            if 'end' in period:
                dates.append(period['end'][:10])
            elif 'start' in period:
                dates.append(period['start'][:10])
    if dates:
        latest_vaccine_date = max(dates)
# Output: latest_vaccine_date (str or None)

