def parse_date(resource):
    # Try common FHIR date fields in Procedure/MedicationRequest resources
    date_fields = ['performedDateTime', 'performedPeriod', 'authoredOn', 'occurrenceDateTime']
    for field in date_fields:
        val = resource.get(field)
        if isinstance(val, str):
            return val[:10]  # ISO 8601 date
        elif isinstance(val, dict):
            # For Period, take 'end' if present, else 'start'
            if 'end' in val:
                return val['end'][:10]
            elif 'start' in val:
                return val['start'][:10]
    return None

